    const interrupted: OperationState = {
      ...state,
      status: "interrupted",
      interruption_reason_code: "user_stop",
      error: "Stopped by user",
      updated_at: new Date().toISOString(),
    };
    setState(interrupted);
    await persistState(interrupted);
  }, [state, persistState]);

